from __future__ import annotations

import os
import json
import shlex
import shutil
import subprocess
import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
FRONTEND_APPS = (
    Path("apps/admin-dashboard"),
    Path("apps/patient-portal"),
    Path("apps/provider-portal"),
    Path("apps/integration-console"),
    Path("apps/public-website"),
)
IGNORED_DIRS = {
    ".git",
    ".pytest_cache",
    ".venv",
    "__pycache__",
    "build",
    "dist",
    "node_modules",
}
REQUIRED_DIRECTORIES = (
    Path("apps"),
    Path("compliance"),
    Path("database"),
    Path("docs"),
    Path("infrastructure"),
    Path("infrastructure/docker"),
    Path("infrastructure/helm/healthbridge"),
    Path("packages"),
    Path("scripts"),
    Path("services"),
    Path("tests"),
)
REQUIRED_FILES = (
    Path("docker-compose.yml"),
    Path("package.json"),
    Path("package-lock.json"),
    Path("pyproject.toml"),
)


def relative(path: Path) -> str:
    return path.relative_to(ROOT).as_posix()


def format_command(command: list[str | Path]) -> str:
    return " ".join(shlex.quote(str(part)) for part in command)


def run(command: list[str | Path], cwd: Path = ROOT) -> None:
    location = "" if cwd == ROOT else f" (cwd: {relative(cwd)})"
    print(f"+ {format_command(command)}{location}")
    subprocess.run([str(part) for part in command], cwd=cwd, check=True)


def skip(message: str) -> None:
    print(f"SKIP: {message}")


def require_paths(paths: tuple[Path, ...], *, directory: bool) -> None:
    missing = []
    for path in paths:
        full_path = ROOT / path
        if directory and not full_path.is_dir():
            missing.append(path.as_posix())
        if not directory and not full_path.is_file():
            missing.append(path.as_posix())
    if missing:
        kind = "directories" if directory else "files"
        raise FileNotFoundError(f"missing required {kind}: {', '.join(missing)}")


def verify_project_structure() -> None:
    require_paths(REQUIRED_DIRECTORIES, directory=True)
    require_paths(REQUIRED_FILES, directory=False)
    print(
        "validated required project structure "
        f"({len(REQUIRED_DIRECTORIES)} directories, {len(REQUIRED_FILES)} files)"
    )


def load_json(path: Path) -> object:
    with path.open(encoding="utf-8") as handle:
        return json.load(handle)


def verify_frontend_metadata() -> None:
    root_package = load_json(ROOT / "package.json")
    if not isinstance(root_package, dict):
        raise ValueError("package.json must contain a JSON object")
    workspaces = root_package.get("workspaces")
    if not isinstance(workspaces, list):
        raise ValueError("package.json must define a workspaces array")

    missing_workspaces = [
        app.as_posix() for app in FRONTEND_APPS if app.as_posix() not in workspaces
    ]
    if missing_workspaces:
        raise ValueError(
            "root package.json is missing frontend workspaces: "
            + ", ".join(missing_workspaces)
        )

    for app in FRONTEND_APPS:
        package_json = ROOT / app / "package.json"
        package_lock = ROOT / app / "package-lock.json"
        if not package_json.is_file():
            raise FileNotFoundError(f"missing frontend package file: {relative(package_json)}")
        if not package_lock.is_file():
            raise FileNotFoundError(f"missing frontend lockfile: {relative(package_lock)}")

        app_package = load_json(package_json)
        if not isinstance(app_package, dict):
            raise ValueError(f"{relative(package_json)} must contain a JSON object")
        scripts = app_package.get("scripts")
        if not isinstance(scripts, dict):
            raise ValueError(f"{relative(package_json)} must define scripts")
        for script in ("test", "build"):
            if script not in scripts:
                raise ValueError(f"{relative(package_json)} is missing '{script}' script")

    print(f"validated root npm workspace metadata and {len(FRONTEND_APPS)} app lockfiles")


def iter_files_with_suffixes(suffixes: tuple[str, ...]) -> list[Path]:
    matches: list[Path] = []
    for current_root, dirnames, filenames in os.walk(ROOT):
        dirnames[:] = [dirname for dirname in dirnames if dirname not in IGNORED_DIRS]
        current_path = Path(current_root)
        for filename in filenames:
            if filename.endswith(suffixes):
                matches.append(current_path / filename)
    return sorted(matches)


def validate_json() -> None:
    count = 0
    for path in iter_files_with_suffixes((".json",)):
        load_json(path)
        count += 1
    print(f"validated {count} json files")


def is_helm_template(path: Path) -> bool:
    parts = path.relative_to(ROOT).parts
    return (
        len(parts) >= 4
        and parts[0] == "infrastructure"
        and parts[1] == "helm"
        and "templates" in parts
    )


def validate_yaml_with_pyyaml(paths: list[Path]) -> bool:
    try:
        import yaml
    except Exception:
        return False

    for path in paths:
        with path.open(encoding="utf-8") as handle:
            list(yaml.safe_load_all(handle))
    return True


def validate_yaml_with_node(paths: list[Path]) -> bool:
    if shutil.which("node") is None:
        return False

    script = r"""
const fs = require("fs");
const YAML = require("yaml");
const paths = JSON.parse(fs.readFileSync(0, "utf8"));
const failures = [];
for (const path of paths) {
  const source = fs.readFileSync(path, "utf8");
  const docs = YAML.parseAllDocuments(source);
  for (const doc of docs) {
    for (const error of doc.errors) {
      failures.push(`${path}: ${error.message}`);
    }
  }
}
if (failures.length > 0) {
  console.error(failures.join("\n"));
  process.exit(1);
}
"""
    print("+ node -e <yaml validation script>")
    subprocess.run(
        ["node", "-e", script],
        cwd=ROOT,
        input=json.dumps([str(path) for path in paths]),
        text=True,
        check=True,
    )
    return True


def validate_yaml() -> None:
    paths = [
        path
        for path in iter_files_with_suffixes((".yaml", ".yml"))
        if not is_helm_template(path)
    ]
    if not validate_yaml_with_pyyaml(paths) and not validate_yaml_with_node(paths):
        raise RuntimeError(
            "YAML validation requires PyYAML or the root npm 'yaml' dependency. "
            "Run npm install from the repository root."
        )
    print(f"validated {len(paths)} non-template yaml files")


def run_services() -> None:
    for app in sorted((ROOT / "services").glob("*/app.py")):
        run([sys.executable, str(app)])


def run_frontends() -> None:
    run(["npm", "test"])
    run(["npm", "run", "build"])


def check_go_sdk() -> None:
    sdk_dir = ROOT / "packages/sdk-go"
    if not (sdk_dir / "go.mod").is_file():
        raise FileNotFoundError("packages/sdk-go/go.mod is required")
    if shutil.which("go") is None:
        skip("Go SDK tests: go not found on PATH")
        return
    run(["go", "test", "./..."], cwd=sdk_dir)


def check_helm_chart() -> None:
    chart_dir = ROOT / "infrastructure/helm/healthbridge"
    if not (chart_dir / "Chart.yaml").is_file():
        raise FileNotFoundError("infrastructure/helm/healthbridge/Chart.yaml is required")
    if not (chart_dir / "values.yaml").is_file():
        raise FileNotFoundError("infrastructure/helm/healthbridge/values.yaml is required")
    if shutil.which("helm") is None:
        skip("Helm chart lint: helm not found on PATH")
        return
    run(["helm", "lint", chart_dir])


def check_database() -> None:
    schema = ROOT / "database/schema.sql"
    migrations = sorted((ROOT / "database/migrations").glob("*.sql"))
    if not schema.is_file():
        raise FileNotFoundError("database/schema.sql is required")
    if not migrations:
        raise FileNotFoundError("database/migrations must contain SQL migrations")
